const data = $input.all();
const result = {
  "重复激活数据": [],
  "激活设备无SN数据": [],
  "激活数据插入数据库失败": []
};

data[0].json.item.forEach(item => {
  if (item.hasOwnProperty("重复激活数据")) {
    result["重复激活数据"].push(item["重复激活数据"]["SN"]);
  } else if (item.hasOwnProperty("激活设备无SN数据")) {
    result["激活设备无SN数据"].push(item["激活设备无SN数据"]["uuid"]);
  } else if (item.hasOwnProperty("激活数据插入数据库失败")) {
    result["激活数据插入数据库失败"].push(item["激活数据插入数据库失败"]["SN"]);
  }
});
return result;

